arguments.file_text:
.message-item {
    position: relative;
    padding: 8px 16px;
    transition: background-color 0.1s;
}

.message-item:hover {
    background-color: #f8f8f8;
}

.message-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.author {
    font-weight: 700;
    font-size: 0.92rem;
    color: #1a1a1a;
}

.timestamp {
    font-size: 0.75rem;
    color: #999;
}

.message-content {
    font-size: 0.9rem;
    color: #333;
    line-height: 1.5;
    white-space: pre-wrap;
    word-wrap: break-word;
}

.reactions {
    display: flex;
    flex-wrap: wrap;
    gap: 4px;
    margin-top: 6px;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 4px;
    padding: 2px 8px;
    border: 1px solid #e0e0e0;
    border-radius: 12px;
    background: #f5f5f5;
    font-size: 0.82rem;
    cursor: pointer;
    transition: background-color 0.15s;
}

.reaction-badge:hover {
    background: #e8e8e8;
    border-color: #ccc;
}

.reaction-count {
    font-size: 0.78rem;
    color: #555;
}

.thread-link {
    display: inline-block;
    margin-top: 4px;
    font-size: 0.82rem;
    color: #4a90d9;
    background: none;
    border: none;
    cursor: pointer;
    padding: 2px 0;
    font-weight: 500;
}

.thread-link:hover {
    text-decoration: underline;
}

.action-bar {
    position: absolute;
    top: -14px;
    right: 16px;
    display: flex;
    gap: 2px;
    background: #fff;
    border: 1px solid #e0e0e0;
    border-radius: 6px;
    box-shadow: 0 1px 4px rgba(0, 0, 0, 0.1);
    padding: 2px;
    z-index: 10;
}

.action-btn {
    padding: 4px 10px;
    border: none;
    background: transparent;
    font-size: 0.8rem;
    cursor: pointer;
    border-radius: 4px;
    white-space: nowrap;
    color: #555;
}

.action-btn:hover {
    background: #f0f0f0;
    color: #333;
}

.emoji-picker-wrapper {
    position: relative;
}

.emoji-picker {
    position: absolute;
    top: 100%;
    right: 0;
    margin-top: 4px;
    display: flex;
    gap: 2px;
    background: #fff;
    border: 1px solid #e0e0e0;
    border-radius: 8px;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.12);
    padding: 6px;
    z-index: 20;
}

.emoji-option {
    padding: 4px 6px;
    border: none;
    background: transparent;
    font-size: 1.2rem;
    cursor: pointer;
    border-radius: 4px;
    transition: background-color 0.1s;
}

.emoji-option:hover {
    background: #f0f0f0;
}

@namespace sv_28cd7a49e1514a65bbe6f0c933ad9ae0.Components.Chat

<div class="channel-sidebar">
    <div class="sidebar-header">
        <h2>Channels</h2>
    </div>
    <div class="channel-list">
        @foreach (var channel in Channels)
        {
            <ChannelItem Channel="channel"
                         IsActive="channel.Id == ActiveChannelId"
                         OnClick="() => OnChannelSelected.InvokeAsync(channel.Id)" />
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired] public required List<Channel> Channels { get; set; }
    [Parameter] public int ActiveChannelId { get; set; }
    [Parameter] public EventCallback<int> OnChannelSelected { get; set; }
}

.channel-sidebar {
    display: flex;
    flex-direction: column;
    height: 100%;
    background-color: #2c2f33;
    color: #dcddde;
}

.sidebar-header {
    padding: 16px;
    border-bottom: 1px solid rgba(255, 255, 255, 0.08);
}

.sidebar-header h2 {
    margin: 0;
    font-size: 1.1rem;
    font-weight: 700;
    color: #fff;
}

.channel-list {
    flex: 1;
    overflow-y: auto;
    padding: 8px;
}

@namespace sv_28cd7a49e1514a65bbe6f0c933ad9ae0.Components.Chat
@inject IJSRuntime JS

<div class="message-list-container">
    <div class="message-scroll" @ref="scrollContainer">
        @if (IsLoadingOlder)
        {
            <div class="loading-indicator">Loading older messages…</div>
        }
        @if (HasMoreMessages)
        {
            <div class="load-more-sentinel" @ref="sentinelElement"></div>
        }
        @foreach (var message in Messages)
        {
            <MessageItem Message="message"
                         ThreadInfo="GetThreadInfo(message.Id)"
                         OnOpenThread="OnOpenThread"
                         OnReact="OnReact" />
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired] public required List<Message> Messages { get; set; }
    [Parameter] public Dictionary<int, ThreadSummary>? ThreadSummaries { get; set; }
    [Parameter] public bool HasMoreMessages { get; set; }
    [Parameter] public bool IsLoadingOlder { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    private ElementReference scrollContainer;
    private ElementReference sentinelElement;
    private IJSObjectReference? module;
    private DotNetObjectReference<MessageList>? dotNetRef;

    private ThreadSummary? GetThreadInfo(int messageId)
        => ThreadSummaries?.GetValueOrDefault(messageId);

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            module = await JS.InvokeAsync<IJSObjectReference>("import",
