@namespace sv_28cd7a49e1514a65bbe6f0c933ad9ae0.Components.Chat

<div class="thread-panel">
    <div class="thread-header">
        <h3>Thread</h3>
        <button class="close-btn" @onclick="OnClose" title="Close thread">✕</button>
    </div>

    <div class="thread-root-message">
        <div class="root-author">@RootMessage.Author</div>
        <div class="root-content">@RootMessage.Content</div>
    </div>

    <div class="thread-divider">
        <span>@Replies.Count @(Replies.Count == 1 ? "reply" : "replies")</span>
    </div>

    <div class="thread-replies">
        @foreach (var reply in Replies)
        {
            <div class="thread-reply">
                <div class="reply-header">
                    <span class="reply-author">@reply.Author</span>
                    <span class="reply-time">@FormatRelativeTime(reply.SentAt)</span>
                </div>
                <div class="reply-content">@reply.Content</div>
            </div>
        }
    </div>

    <MessageInput Placeholder="Reply in thread…"
                  ButtonText="Reply"
                  OnSubmit="OnReply" />
</div>

@code {
    [Parameter, EditorRequired] public required Message RootMessage { get; set; }
    [Parameter, EditorRequired] public required List<Message> Replies { get; set; }
    [Parameter] public EventCallback OnClose { get; set; }
    [Parameter] public EventCallback<string> OnReply { get; set; }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt.ToUniversalTime();

        return diff.TotalSeconds switch
        {
            < 60 => "just now",
            < 3600 => $"{(int)diff.TotalMinutes} min ago",
            < 86400 => $"{(int)diff.TotalHours}h ago",
            < 604800 => $"{(int)diff.TotalDays}d ago",
            _ => sentAt.ToString("MMM d, yyyy")
        };
    }
}

.thread-panel {
    display: flex;
    flex-direction: column;
    height: 100%;
    border-left: 1px solid #e0e0e0;
    background: #fff;
}

.thread-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 12px 16px;
    border-bottom: 1px solid #e0e0e0;
}

.thread-header h3 {
    margin: 0;
    font-size: 1rem;
    font-weight: 700;
}

.close-btn {
    background: none;
    border: none;
    font-size: 1.1rem;
    cursor: pointer;
    color: #777;
    padding: 4px 8px;
    border-radius: 4px;
    transition: background-color 0.15s;
}

.close-btn:hover {
    background: #f0f0f0;
    color: #333;
}

.thread-root-message {
    padding: 12px 16px;
    background: #f9f9f9;
    border-bottom: 1px solid #e0e0e0;
}

.root-author {
    font-weight: 700;
    font-size: 0.9rem;
    margin-bottom: 4px;
}

.root-content {
    font-size: 0.88rem;
    color: #333;
    line-height: 1.4;
    white-space: pre-wrap;
    word-wrap: break-word;
}

.thread-divider {
    padding: 8px 16px;
    font-size: 0.78rem;
    color: #999;
    border-bottom: 1px solid #f0f0f0;
}

.thread-replies {
    flex: 1;
    overflow-y: auto;
    padding: 4px 0;
}

.thread-reply {
    padding: 8px 16px;
}

.reply-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.reply-author {
    font-weight: 700;
    font-size: 0.88rem;
}

.reply-time {
    font-size: 0.72rem;
    color: #999;
}

.reply-content {
    font-size: 0.88rem;
    color: #333;
    line-height: 1.4;
    white-space: pre-wrap;
    word-wrap: break-word;
}

