arguments.file_text:
@page "/chat"
@layout ChatLayout
@rendermode InteractiveServer

@namespace sv_28cd7a49e1514a65bbe6f0c933ad9ae0.Components.Pages
@using sv_28cd7a49e1514a65bbe6f0c933ad9ae0.Components.Chat
@inject IChatService ChatService

<PageTitle>Chat</PageTitle>

<div class="chat-container">
    <div class="sidebar-panel">
        <ChannelSidebar Channels="channels"
                        ActiveChannelId="selectedChannelId"
                        OnChannelSelected="SelectChannel" />
    </div>

    <div class="main-panel @(isThreadOpen ? "with-thread" : "")">
        @if (selectedChannel is not null)
        {
            <div class="channel-header">
                <h2># @selectedChannel.Name</h2>
                <p>@selectedChannel.Description</p>
            </div>

            <MessageList @ref="messageList"
                         Messages="messages"
                         ThreadSummaries="threadSummaries"
                         HasMoreMessages="hasMoreMessages"
                         IsLoadingOlder="isLoadingOlder"
                         OnLoadMore="LoadOlderMessages"
                         OnOpenThread="OpenThread"
                         OnReact="HandleReaction" />

            <MessageInput Placeholder="@($"Message #{selectedChannel.Name}")"
                          OnSubmit="SendMessage" />
        }
        else
        {
            <div class="no-channel">
                <p>Select a channel to start chatting</p>
            </div>
        }
    </div>

    @if (isThreadOpen && threadRootMessage is not null)
    {
        <div class="thread-panel-container">
            <ThreadPanel RootMessage="threadRootMessage"
                         Replies="threadReplies"
                         OnClose="CloseThread"
                         OnReply="SendThreadReply" />
        </div>
    }
</div>

@code {
    private List<Channel> channels = [];
    private List<Message> messages = [];
    private List<Message> threadReplies = [];
    private Dictionary<int, ThreadSummary> threadSummaries = [];

    private Channel? selectedChannel;
