+                         ThreadSummaries="threadSummaries"
+                         HasMoreMessages="hasMoreMessages"
+                         IsLoadingOlder="isLoadingOlder"
+                         OnLoadMore="LoadOlderMessages"
+                         OnOpenThread="OpenThread"
+                         OnReact="HandleReaction" />
+
+            <MessageInput Placeholder="@($"Message #{selectedChannel.Name}")"
+                          OnSubmit="SendMessage" />
+        }
+        else
+        {
+            <div class="no-channel">
+                <p>Select a channel to start chatting</p>
+            </div>
+        }
+    </div>
+
+    @if (isThreadOpen && threadRootMessage is not null)
+    {
+        <div class="thread-panel-container">
+            <ThreadPanel RootMessage="threadRootMessage"
+                         Replies="threadReplies"
+                         OnClose="CloseThread"
+                         OnReply="SendThreadReply" />
+        </div>
+    }
+</div>
+
+@code {
+    private List<Channel> channels = [];
+    private List<Message> messages = [];
+    private List<Message> threadReplies = [];
+    private Dictionary<int, ThreadSummary> threadSummaries = [];
+
+    private Channel? selectedChannel;
+    private int selectedChannelId;
+    private Message? threadRootMessage;
+    private MessageList? messageList;
+
+    private bool isThreadOpen;
+    private bool hasMoreMessages = true;
+    private bool isLoadingOlder;
+    private const int PageSize = 30;
+
+    protected override async Task OnInitializedAsync()
+    {
+        channels = await ChatService.GetChannelsAsync();
+        if (channels.Count > 0)
+        {
+            await SelectChannel(channels[0].Id);
+        }
+    }
+
+    private async Task SelectChannel(int channelId)
+    {
+        selectedChannelId = channelId;
+        selectedChannel = channels.FirstOrDefault(c => c.Id == channelId);
+        messages = [];
+        threadSummaries = [];
+        hasMoreMessages = true;
+        isThreadOpen = false;
+        threadRootMessage = null;
+
+        var loaded = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
+        messages = loaded;
+        hasMoreMessages = loaded.Count >= PageSize;
+        BuildThreadSummaries();
+
+        _ = ChatService.MarkChannelReadAsync(channelId);
+    }
+
+    private async Task LoadOlderMessages()
+    {
+        if (isLoadingOlder || !hasMoreMessages || selectedChannel is null) return;
+
+        isLoadingOlder = true;
+        StateHasChanged();
+
+        var older = await ChatService.GetMessagesAsync(selectedChannel.Id, messages.Count, PageSize);
+        if (older.Count < PageSize)
+        {
+            hasMoreMessages = false;
+        }
+
+        messages.InsertRange(0, older);
+        BuildThreadSummaries();
+
+        isLoadingOlder = false;
+    }
+
+    private async Task SendMessage(string content)
+    {
+        if (selectedChannel is null) return;
+
+        var msg = await ChatService.SendMessageAsync(selectedChannel.Id, content, null);
+        messages.Add(msg);
+
+        if (messageList is not null)
+        {
+            await messageList.ScrollToBottom();
+        }
+    }
+
+    private async Task OpenThread(int rootMessageId)
+    {
+        threadRootMessage = messages.FirstOrDefault(m => m.Id == rootMessageId);
+        if (threadRootMessage is null) return;
+
+        threadReplies = await ChatService.GetThreadAsync(rootMessageId);
+        isThreadOpen = true;
+    }
+
+    private void CloseThread()
+    {
+        isThreadOpen = false;
+        threadRootMessage = null;
+        threadReplies = [];
+    }
+
+    private async Task SendThreadReply(string content)
+    {
+        if (threadRootMessage is null || selectedChannel is null) return;
+
+        var reply = await ChatService.SendMessageAsync(selectedChannel.Id, content, threadRootMessage.Id);
+        threadReplies.Add(reply);
+
+        // Update thread summary in main view
+        if (threadSummaries.ContainsKey(threadRootMessage.Id))
+        {
+            var existing = threadSummaries[threadRootMessage.Id];
+            threadSummaries[threadRootMessage.Id] = existing with
+            {
+                ReplyCount = existing.ReplyCount + 1,
+                LastReplyAt = reply.SentAt
+            };
+        }
+        else
+        {
+            threadSummaries[threadRootMessage.Id] = new ThreadSummary(threadRootMessage.Id, 1, reply.SentAt);
+        }
+    }
+
+    private async Task HandleReaction((int MessageId, string Emoji) args)
+    {
+        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);
+
+        // Optimistically update the local message
+        var msg = messages.FirstOrDefault(m => m.Id == args.MessageId);
+        if (msg is null) return;
+
+        var existing = msg.Reactions.FirstOrDefault(r => r.Emoji == args.Emoji);
+        if (existing is not null)
+        {
+            existing.Users.Add("You");
+        }
+        else
+        {
+            msg.Reactions.Add(new Reaction(args.Emoji, ["You"]));
+        }
+    }
+
+    private void BuildThreadSummaries()
+    {
+        // Build summaries from messages that are replies
+        var repliesByRoot = messages
+            .Where(m => m.ReplyToId.HasValue)
+            .GroupBy(m => m.ReplyToId!.Value);
+
+        foreach (var group in repliesByRoot)
+        {
+            var replies = group.ToList();
+            threadSummaries[group.Key] = new ThreadSummary(
+                group.Key,
+                replies.Count,
+                replies.Max(r => r.SentAt));
+        }
+    }
+}
+

