toolArgs.file_text:
.chat-container {
    display: flex;
    height: 100vh;
    overflow: hidden;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
}

.sidebar-panel {
    width: 20%;
    min-width: 200px;
    max-width: 280px;
    flex-shrink: 0;
}

.main-panel {
    flex: 1;
    display: flex;
    flex-direction: column;
    min-width: 0;
    background: #fff;
}

.main-panel.with-thread {
    max-width: calc(100% - 20% - 25%);
}

.thread-panel-container {
    width: 25%;
    min-width: 280px;
    max-width: 400px;
    flex-shrink: 0;
}

.channel-header {
    padding: 12px 20px;
    border-bottom: 1px solid #e0e0e0;
    flex-shrink: 0;
}

.channel-header h2 {
    margin: 0;
    font-size: 1.1rem;
    font-weight: 700;
    color: #1a1a1a;
}

.channel-header p {
    margin: 2px 0 0;
    font-size: 0.82rem;
    color: #777;
}

.no-channel {
    flex: 1;
    display: flex;
    align-items: center;
    justify-content: center;
    color: #999;
    font-size: 1rem;
}

